UPDATE public.media_titles SET title='Annihilation',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/4YRplSk6BhH6PRuE9gfyw9byUJ6.jpg',poster_url),description='A biologist signs up for a dangerous, secret expedition into a mysterious zone where the laws of nature don''t apply.',release_year=2018,genres=COALESCE('{"Science Fiction","Horror"}',genres),cast_members=COALESCE('{"Natalie Portman","Jennifer Jason Leigh","Gina Rodriguez","Tessa Thompson","Tuva Novotny","Oscar Isaac"}',cast_members),directors=COALESCE('{"Alex Garland"}',directors),rating=COALESCE(6.4,rating),external_source='tmdb',external_id='movie-300668' WHERE id='1c9efd87-02a5-4362-ab06-12863bd2f822';
