UPDATE public.media_titles SET title='Better Call Saul',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/zjg4jpK1Wp2kiRvtt5ND0kznako.jpg',poster_url),description='Six years before Saul Goodman meets Walter White. We meet him when the man who will become Saul Goodman is known as Jimmy McGill, a small-time lawyer searching for his destiny, and, more immediately, hustling to make ends meet. Working alongside, and, often, against Jimmy, is “fixer” Mike Ehrmantraut. The series tracks Jimmy’s transformation into Saul Goodman, the man who puts “criminal” in “criminal lawyer".',release_year=2015,genres=COALESCE('{"Crime","Drama"}',genres),cast_members=COALESCE('{"Bob Odenkirk","Jonathan Banks","Rhea Seehorn","Tony Dalton","Giancarlo Esposito"}',cast_members),directors=COALESCE(NULL,directors),rating=COALESCE(8.7,rating),external_source='tmdb',external_id='tv-60059' WHERE id='554e7e9a-f642-400d-bb56-c794d1bd192b';
UPDATE public.media_titles SET title='Black Mirror',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/seN6rRfN0I6n8iDXjlSMk1QjNcq.jpg',poster_url),description='Twisted tales run wild in this mind-bending anthology series that reveals humanity''s worst traits, greatest innovations and more.',release_year=2011,genres=COALESCE('{"Sci-Fi & Fantasy","Drama","Mystery"}',genres),cast_members=COALESCE(NULL,cast_members),directors=COALESCE(NULL,directors),rating=COALESCE(8.3,rating),external_source='tmdb',external_id='tv-42009' WHERE id='ee4f49ee-aa61-437f-872b-ab3246074d3e';
