UPDATE public.media_titles SET title='Fleabag',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/27vEYsRKa3eAniwmoccOoluEXQ1.jpg',poster_url),description='A portrait into the mind of a dry-witted, sexual, angry, porn-watching, grief-riddled woman, trying to make sense of the world. As she hurls herself headlong at modern living, Fleabag is thrown roughly up against the walls of contemporary London, with all its frenetic energy, late nights, and bright lights.',release_year=2016,genres=COALESCE('{"Comedy","Drama"}',genres),cast_members=COALESCE('{"Phoebe Waller-Bridge","Sian Clifford","Andrew Scott"}',cast_members),directors=COALESCE(NULL,directors),rating=COALESCE(8.3,rating),external_source='tmdb',external_id='tv-67070' WHERE id='bb6e03a2-153e-4497-948b-529351553952';
UPDATE public.media_titles SET title='Game of Thrones',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/1XS1oqL89opfnbLl8WnZY1O1uJx.jpg',poster_url),description='Seven noble families fight for control of the mythical land of Westeros. Friction between the houses leads to full-scale war. All while a very ancient evil awakens in the farthest north. Amidst the war, a neglected military order of misfits, the Night''s Watch, is all that stands between the realms of men and icy horrors beyond.',release_year=2011,genres=COALESCE('{"Sci-Fi & Fantasy","Drama","Action & Adventure"}',genres),cast_members=COALESCE('{"Peter Dinklage","Kit Harington","Nikolaj Coster-Waldau","Lena Headey","Emilia Clarke","Liam Cunningham"}',cast_members),directors=COALESCE(NULL,directors),rating=COALESCE(8.5,rating),external_source='tmdb',external_id='tv-1399' WHERE id='a2a658cf-4f3a-4cc7-8766-70ac09e588e5';
