UPDATE public.media_titles SET title='Inception',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/xlaY2zyzMfkhk0HSC5VUwzoZPU1.jpg',poster_url),description='Cobb, a skilled thief who commits corporate espionage by infiltrating the subconscious of his targets is offered a chance to regain his old life as payment for a task considered to be impossible: "inception", the implantation of another person''s idea into a target''s subconscious.',release_year=2010,genres=COALESCE('{"Action","Science Fiction","Adventure"}',genres),cast_members=COALESCE('{"Leonardo DiCaprio","Joseph Gordon-Levitt","Ken Watanabe","Tom Hardy","Elliot Page","Dileep Rao"}',cast_members),directors=COALESCE('{"Christopher Nolan"}',directors),rating=COALESCE(8.4,rating),external_source='tmdb',external_id='movie-27205' WHERE id='7442477e-2c86-4458-9cf9-2bdbf84b76f8';
