UPDATE public.media_titles SET title='Knives Out',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/pThyQovXQrw2m0s9x82twj48Jq4.jpg',poster_url),description='When renowned crime novelist Harlan Thrombey is found dead at his estate just after his 85th birthday, the inquisitive and debonair Detective Benoit Blanc is mysteriously enlisted to investigate. From Harlan''s dysfunctional family to his devoted staff, Blanc sifts through a web of red herrings and self-serving lies to uncover the truth behind Harlan''s untimely death.',release_year=2019,genres=COALESCE('{"Comedy","Crime","Mystery"}',genres),cast_members=COALESCE('{"Daniel Craig","Chris Evans","Ana de Armas","Jamie Lee Curtis","Michael Shannon","Don Johnson"}',cast_members),directors=COALESCE('{"Rian Johnson"}',directors),rating=COALESCE(7.8,rating),external_source='tmdb',external_id='movie-546554' WHERE id='ff2833ce-1b27-40ff-b7b2-c511948bd407';
UPDATE public.media_titles SET title='La La Land',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/uDO8zWDhfWwoFdKS4fzkUJt0Rf0.jpg',poster_url),description='Mia, an aspiring actress, serves lattes to movie stars in between auditions and Sebastian, a jazz musician, scrapes by playing cocktail party gigs in dingy bars, but as success mounts they are faced with decisions that begin to fray the fragile fabric of their love affair, and the dreams they worked so hard to maintain in each other threaten to rip them apart.',release_year=2016,genres=COALESCE('{"Comedy","Drama","Romance"}',genres),cast_members=COALESCE('{"Ryan Gosling","Emma Stone","John Legend","Rosemarie DeWitt","Finn Wittrock","Callie Hernandez"}',cast_members),directors=COALESCE('{"Damien Chazelle"}',directors),rating=COALESCE(7.9,rating),external_source='tmdb',external_id='movie-313369' WHERE id='21141e04-2425-4611-b3dd-c897b00916f7';
