UPDATE public.media_titles SET title='Manifest',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/eTemCphrglLKrXOsNRhYezHA7H9.jpg',poster_url),description='After landing from a turbulent but routine flight, the crew and passengers of Montego Air Flight 828 discover five years have passed in what seemed like a few hours. As their new realities become clear, a deeper mystery unfolds and some of the returned passengers soon realize they may be meant for something greater than they ever thought possible.',release_year=2018,genres=COALESCE('{"Sci-Fi & Fantasy","Mystery","Drama"}',genres),cast_members=COALESCE('{"Melissa Roxburgh","Josh Dallas","J.R. Ramirez","Luna Blaise","Parveen Kaur","Matt Long"}',cast_members),directors=COALESCE(NULL,directors),rating=COALESCE(7.6,rating),external_source='tmdb',external_id='movie-79696' WHERE id='af3b1d72-f9ad-49de-a555-fd4cf35331c8';
