UPDATE public.media_titles SET title='Mr. Robot',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/kv1nRqgebSsREnd7vdC2pSGjpLo.jpg',poster_url),description='A young programmer, Elliot, suffers from a debilitating anti-social disorder and decides that he can only connect to people by hacking them. He wields his skills as a weapon to protect the people that he cares about. Elliot finds himself in the intersection between a cybersecurity firm he works for and the underworld organizations that are recruiting him to bring down corporate America.',release_year=2015,genres=COALESCE('{"Crime","Drama"}',genres),cast_members=COALESCE('{"Rami Malek","Christian Slater","Carly Chaikin"}',cast_members),directors=COALESCE(NULL,directors),rating=COALESCE(8.3,rating),external_source='tmdb',external_id='tv-62560' WHERE id='6747d52a-e1b4-4e3a-8f27-7f4ee03bc3d1';
