UPDATE public.media_titles SET title='Peaky Blinders',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/vUUqzWa2LnHIVqkaKVlVGkVcZIW.jpg',poster_url),description='A gangster family epic set in 1919 Birmingham, England and centered on a gang who sew razor blades in the peaks of their caps, and their fierce boss Tommy Shelby, who means to move up in the world.',release_year=2013,genres=COALESCE('{"Drama","Crime"}',genres),cast_members=COALESCE('{"Cillian Murphy","Paul Anderson","Sophie Rundle","Natasha O''Keeffe"}',cast_members),directors=COALESCE(NULL,directors),rating=COALESCE(8.5,rating),external_source='tmdb',external_id='tv-60574' WHERE id='c9e6baf0-2697-43ea-8fe4-8974e5e8ae77';
