UPDATE public.media_titles SET title='Terrifier 2',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/qEAlwXbYk6IHA4ztoS2XFFaa7Xo.jpg',poster_url),description='A year after the Miles County massacre, Art the Clown is resurrected by a sinister entity. Art returns home, where he must hunt down and destroy teenage Sienna and her younger brother Jonathan on Halloween. As the body count rises, the siblings fight to stay alive while uncovering the true nature of Art''s evil intent.',release_year=2022,genres=COALESCE('{"Horror"}',genres),cast_members=COALESCE('{"David Howard Thornton","Lauren LaVera","Elliott Fullam","Sarah Voigt","Kailey Hyman","Casey Hartnett"}',cast_members),directors=COALESCE('{"Damien Leone"}',directors),rating=COALESCE(6.7,rating),external_source='tmdb',external_id='movie-663712' WHERE id='04b1752d-df00-430c-abc8-51f14f953f75';
