UPDATE public.media_titles SET title='The Crown',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/1M876KPjulVwppEpldhdc8V4o68.jpg',poster_url),description='The gripping, decades-spanning inside story of Her Majesty Queen Elizabeth II and the Prime Ministers who shaped Britain''s post-war destiny.

The Crown tells the inside story of two of the most famous addresses in the world – Buckingham Palace and 10 Downing Street – and the intrigues, love lives and machinations behind the great events that shaped the second half of the 20th century. Two houses, two courts, one Crown.',release_year=2016,genres=COALESCE('{"Drama"}',genres),cast_members=COALESCE('{"Imelda Staunton","Jonathan Pryce","Lesley Manville","Dominic West","Claudia Harrison","Marcia Warren"}',cast_members),directors=COALESCE(NULL,directors),rating=COALESCE(8.2,rating),external_source='tmdb',external_id='tv-65494' WHERE id='7fbc785d-2f0a-4f99-b28c-e80b658ec814';
UPDATE public.media_titles SET title='The Good Place',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/qIhsuhoIYR5yTnDta0IL4senbeN.jpg',poster_url),description='Eleanor Shellstrop, an ordinary woman who, through an extraordinary string of events, enters the afterlife where she comes to realize that she hasn''t been a very good person. With the help of her wise afterlife mentor, she''s determined to shed her old way of living and discover the awesome (or at least the pretty good) person within.',release_year=2016,genres=COALESCE('{"Sci-Fi & Fantasy","Comedy"}',genres),cast_members=COALESCE('{"Kristen Bell","Ted Danson","William Jackson Harper","Jameela Jamil","Manny Jacinto","D''Arcy Carden"}',cast_members),directors=COALESCE(NULL,directors),rating=COALESCE(8,rating),external_source='tmdb',external_id='tv-66573' WHERE id='41a0e75e-3766-4e22-9361-d6871aa6a859';
UPDATE public.media_titles SET title='The Grand Budapest Hotel',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/eWdyYQreja6JGCzqHWXpWHDrrPo.jpg',poster_url),description='The Grand Budapest Hotel tells of a legendary concierge at a famous European hotel between the wars and his friendship with a young employee who becomes his trusted protégé. The story involves the theft and recovery of a priceless Renaissance painting, the battle for an enormous family fortune and the slow and then sudden upheavals that transformed Europe during the first half of the 20th century.',release_year=2014,genres=COALESCE('{"Comedy","Drama"}',genres),cast_members=COALESCE('{"Ralph Fiennes","F. Murray Abraham","Mathieu Amalric","Adrien Brody","Willem Dafoe","Jeff Goldblum"}',cast_members),directors=COALESCE('{"Wes Anderson"}',directors),rating=COALESCE(8,rating),external_source='tmdb',external_id='movie-120467' WHERE id='4ba33555-a9a4-44fd-8db5-ce32c445441b';
UPDATE public.media_titles SET title='The Lord of the Rings: The Fellowship of the Ring',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/6oom5QYQ2yQTMJIbnvbkBL9cHo6.jpg',poster_url),description='Young hobbit Frodo Baggins, after inheriting a mysterious ring from his uncle Bilbo, must leave his home in order to keep it from falling into the hands of its evil creator. Along the way, a fellowship is formed to protect the ringbearer and make sure that the ring arrives at its final destination: Mt. Doom, the only place where it can be destroyed.',release_year=2001,genres=COALESCE('{"Adventure","Fantasy","Action"}',genres),cast_members=COALESCE('{"Elijah Wood","Ian McKellen","Viggo Mortensen","Sean Astin","Ian Holm","Liv Tyler"}',cast_members),directors=COALESCE('{"Peter Jackson"}',directors),rating=COALESCE(8.4,rating),external_source='tmdb',external_id='movie-120' WHERE id='3bb8467d-bea1-4a50-8a7f-4efde3c050e8';
UPDATE public.media_titles SET title='The Matrix',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/dXNAPwY7VrqMAo51EKhhCJfaGb5.jpg',poster_url),description='Set in the 22nd century, The Matrix tells the story of a computer hacker who joins a group of underground insurgents fighting the vast and powerful computers who now rule the earth.',release_year=1999,genres=COALESCE('{"Action","Science Fiction"}',genres),cast_members=COALESCE('{"Keanu Reeves","Laurence Fishburne","Carrie-Anne Moss","Hugo Weaving","Gloria Foster","Joe Pantoliano"}',cast_members),directors=COALESCE('{"Lana Wachowski","Lilly Wachowski"}',directors),rating=COALESCE(8.2,rating),external_source='tmdb',external_id='movie-603' WHERE id='634b9298-a9d1-4d19-a21f-764f3baf4c41';
