UPDATE public.media_titles SET title='The Shawshank Redemption',poster_url=COALESCE('https://image.tmdb.org/t/p/w780/9cqNxx0GxF0bflZmeSMuL5tnGzr.jpg',poster_url),description='Imprisoned in the 1940s for the double murder of his wife and her lover, upstanding banker Andy Dufresne begins a new life at the Shawshank prison, where he puts his accounting skills to work for an amoral warden. During his long stretch in prison, Dufresne comes to be admired by the other inmates -- including an older prisoner named Red -- for his integrity and unquenchable sense of hope.',release_year=1994,genres=COALESCE('{"Drama","Crime"}',genres),cast_members=COALESCE('{"Tim Robbins","Morgan Freeman","Bob Gunton","William Sadler","Clancy Brown","Gil Bellows"}',cast_members),directors=COALESCE('{"Frank Darabont"}',directors),rating=COALESCE(8.7,rating),external_source='tmdb',external_id='tv-100698' WHERE id='ade94fdc-21bf-456b-8237-493d887b40e4';
